const express = require('express')
const router = express.Router()
const Student = require('../models/Students')


router.post('/add', async (req, res) => {
  try {
    const { firstName, middleName, lastName, gender, department, email, mobile } = req.body

    const existingStudent = await Student.findOne({ email: email })
    if (existingStudent) {
      return res.json({ status: false, message: 'Student already exists!!' })
    }
else{
   const student = new Student({
      firstName,
      middleName,
      lastName,
      gender,
      department,
      email,
      mobile
    })

    await student.save()
    res.json({ status: true, message: 'Student added successfully!' });
  } 

}
  catch (error) {
    console.log('Internal Error:', error);
    res.json({ status: false, message: 'Internal error' });
  }
})

router.get('/get',async(req,res)=>{
  try{
const student=await Student.find()
res.json({ status:true, data: student });
  }
catch (error) {
    console.log('Internal Error:', error);
    res.json({ status: false, message: 'Internal error' });
  }})


  router.delete('/delete/:id',async(req,res)=>{
  try{
    const id=req.params.id
    const deleted = await Student.findByIdAndDelete(id)
    res.json({ status:true, message: 'Student deleted' })
  }
   catch (error) {
    console.log('Internal Error:', error);
    res.json({ status: false, message: 'Internal error' });
  } 
  })

  router.put('/update/:id',async (req,res)=>
  {
  try{
   const id=req.params.id
    const updateObj=req.body
    await Student.findByIdAndUpdate(id,updateObj)
    res.json({status:true,message:'Student Updated'})
   }
   catch (error) {
    console.log('Internal Error:', error);
    res.json({ status: false, message: 'Internal error' });
  } 
  })

module.exports = router
